import {
  addDoc,
  collection,
  doc,
  getDoc,
  onSnapshot,
  orderBy,
  query,
  runTransaction,
  serverTimestamp,
  updateDoc,
} from 'firebase/firestore'
import { createContext, useContext, useEffect, useMemo, useState } from 'react'
import { db, firebaseInitError } from '../services/firebase'
import { uploadIssueImageToSupabase } from '../services/supabase'

const IssueContext = createContext(null)

export function IssueProvider({ children }) {
  const [issues, setIssues] = useState([])
  const [loadingIssues, setLoadingIssues] = useState(true)
  const [firestoreError, setFirestoreError] = useState('')

  useEffect(() => {
    if (!db) {
      setLoadingIssues(false)
      setFirestoreError(firebaseInitError || 'Firestore is not configured correctly.')
      return () => {}
    }
    const q = query(collection(db, 'issues'), orderBy('createdAt', 'desc'))
    const unsubscribe = onSnapshot(
      q,
      (snapshot) => {
        const data = snapshot.docs.map((item) => ({ id: item.id, ...item.data() }))
        setIssues(data)
        setLoadingIssues(false)
        setFirestoreError('')
      },
      (error) => {
        setLoadingIssues(false)
        setIssues([])
        if (error?.code === 'permission-denied') {
          setFirestoreError('Firestore permission denied. Update Firestore security rules in Firebase Console.')
        } else {
          setFirestoreError(error?.message || 'Unable to read issues from Firestore.')
        }
      },
    )
    return unsubscribe
  }, [])

  async function createIssue(formData, userId) {
    if (!db) throw new Error(firebaseInitError || 'Firestore is not configured correctly.')
    let imageUrl = ''
    if (formData.image) {
      imageUrl = await uploadIssueImageToSupabase(formData.image)
    }

    try {
      await addDoc(collection(db, 'issues'), {
        title: formData.title,
        description: formData.description,
        category: formData.category,
        location: formData.location,
        imageUrl,
        status: 'pending',
        upvotes: 0,
        userId,
        createdAt: serverTimestamp(),
      })
    } catch (error) {
      if (error?.code === 'permission-denied') {
        throw new Error('Firestore write blocked by security rules. Please update Firestore rules.')
      }
      throw error
    }

    return { success: true }
  }

  function getIssueById(issueId) {
    return issues.find((item) => item.id === issueId)
  }

  async function hasUserVoted(issueId, userId) {
    if (!db) return false
    const voteRef = doc(db, 'votes', `${issueId}_${userId}`)
    const voteSnap = await getDoc(voteRef)
    return voteSnap.exists()
  }

  async function upvoteIssue(issueId, userId) {
    if (!db) throw new Error(firebaseInitError || 'Firestore is not configured correctly.')
    const issueRef = doc(db, 'issues', issueId)
    const voteRef = doc(db, 'votes', `${issueId}_${userId}`)
    await runTransaction(db, async (transaction) => {
      const voteSnap = await transaction.get(voteRef)
      if (voteSnap.exists()) {
        throw new Error('Already upvoted')
      }

      const issueSnap = await transaction.get(issueRef)
      const currentUpvotes = issueSnap.data()?.upvotes || 0

      transaction.set(voteRef, {
        userId,
        issueId,
        createdAt: serverTimestamp(),
      })
      transaction.update(issueRef, { upvotes: currentUpvotes + 1 })
    })
  }

  async function updateIssueStatus(issueId, status) {
    if (!db) throw new Error(firebaseInitError || 'Firestore is not configured correctly.')
    await updateDoc(doc(db, 'issues', issueId), { status })
  }

  const value = useMemo(
    () => ({
      issues,
      loadingIssues,
      firestoreError,
      createIssue,
      getIssueById,
      hasUserVoted,
      upvoteIssue,
      updateIssueStatus,
    }),
    [issues, loadingIssues, firestoreError],
  )

  return <IssueContext.Provider value={value}>{children}</IssueContext.Provider>
}

export function useIssues() {
  const ctx = useContext(IssueContext)
  if (!ctx) {
    throw new Error('useIssues must be used inside IssueProvider')
  }
  return ctx
}

import { createContext, useCallback, useContext, useMemo, useState } from 'react'

const ToastContext = createContext(null)

export function ToastProvider({ children }) {
  const [toasts, setToasts] = useState([])

  const pushToast = useCallback((message, type = 'info') => {
    const id = crypto.randomUUID()
    setToasts((prev) => [...prev, { id, message, type }])
    setTimeout(() => {
      setToasts((prev) => prev.filter((item) => item.id !== id))
    }, 2800)
  }, [])

  const value = useMemo(() => ({ pushToast }), [pushToast])

  return (
    <ToastContext.Provider value={value}>
      {children}
      <div className="fixed bottom-4 right-4 z-50 space-y-2">
        {toasts.map((toast) => (
          <div
            key={toast.id}
            className={`rounded-xl px-4 py-2 text-sm font-medium shadow-soft ${
              toast.type === 'success'
                ? 'bg-emerald-600 text-white'
                : toast.type === 'error'
                  ? 'bg-rose-600 text-white'
                  : 'bg-slate-800 text-white'
            }`}
          >
            {toast.message}
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  )
}

export function useToast() {
  const ctx = useContext(ToastContext)
  if (!ctx) {
    throw new Error('useToast must be used inside ToastProvider')
  }
  return ctx
}

import { useMemo, useState } from 'react'
import { Link } from 'react-router-dom'
import { motion } from 'framer-motion'
import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts'
import { CheckCircle2, Clock, AlertCircle, TrendingUp, GripVertical } from 'lucide-react'
import { toast } from 'sonner'
import StatusBadge from '../components/StatusBadge'
import { Card } from '../components/ui/card'
import { useIssues } from '../context/IssueContext'
import InteractiveMap from '../components/InteractiveMap'

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#a855f7', '#ef4444']

export default function AuthorityDashboardPage() {
  const { issues, firestoreError, updateIssueStatus } = useIssues()
  const [activeTab, setActiveTab] = useState('kanban')

  const metrics = useMemo(() => {
    const pending = issues.filter((item) => item.status === 'pending').length
    const resolved = issues.filter((item) => item.status === 'resolved').length
    const inProgress = issues.filter((item) => item.status === 'in_progress').length
    return { total: issues.length, pending, resolved, inProgress }
  }, [issues])

  const categoryData = useMemo(() => {
    const counts = {}
    issues.forEach(i => counts[i.category] = (counts[i.category] || 0) + 1)
    return Object.keys(counts).map(k => ({ name: k, value: counts[k] }))
  }, [issues])

  const statusData = [
    { name: 'Pending', count: metrics.pending },
    { name: 'In Progress', count: metrics.inProgress },
    { name: 'Resolved', count: metrics.resolved },
  ]

  const handleDragStart = (e, issueId) => {
    e.dataTransfer.setData("issueId", issueId)
  }

  const handleDrop = async (e, newStatus) => {
    e.preventDefault()
    const issueId = e.dataTransfer.getData("issueId")
    if(issueId) {
      const issue = issues.find(i => i.id === issueId)
      if (issue && issue.status !== newStatus) {
        try {
          await updateIssueStatus(issueId, newStatus)
          toast.success(`Moved to ${newStatus}`)
        } catch(err) {
          toast.error("Failed to update status")
        }
      }
    }
  }

  const handleDragOver = (e) => e.preventDefault()

  const getIssuesByStatus = (status) => issues.filter(i => i.status === status).sort((a,b) => (b.upvotes || 0) - (a.upvotes || 0))

  return (
    <div className="space-y-6 animate-in fade-in zoom-in-95 duration-500">
      <div className="flex flex-col md:flex-row items-start justify-between gap-4 mb-8">
        <div>
          <h1 className="text-3xl font-extrabold text-foreground tracking-tight">Authority Portal</h1>
          <p className="mt-1 text-sm text-muted-foreground">Monitor, assign, and resolve civic issues systematically.</p>
        </div>
        <div className="flex p-1 bg-muted rounded-lg w-full md:w-auto overflow-x-auto shrink-0">
          {['kanban', 'analytics', 'map'].map(tab => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`flex-1 md:w-32 py-2 px-4 text-sm font-medium rounded-md capitalize transition-all whitespace-nowrap ${activeTab === tab ? 'bg-background shadow-sm text-foreground' : 'text-muted-foreground hover:text-foreground'}`}
            >
              {tab}
            </button>
          ))}
        </div>
      </div>

      {firestoreError ? <div className="rounded-xl bg-destructive/10 text-destructive p-4 flex items-center gap-2 border border-destructive/20"><AlertCircle className="w-5 h-5"/> {firestoreError}</div> : null}

      <div className="grid gap-4 grid-cols-2 md:grid-cols-4">
        {[
          { label: 'Total Issues', value: metrics.total, icon: AlertCircle, color: 'text-blue-500', bg: 'bg-blue-500/10' },
          { label: 'Pending Assessment', value: metrics.pending, icon: Clock, color: 'text-amber-500', bg: 'bg-amber-500/10' },
          { label: 'In Progress', value: metrics.inProgress, icon: TrendingUp, color: 'text-purple-500', bg: 'bg-purple-500/10' },
          { label: 'Resolved', value: metrics.resolved, icon: CheckCircle2, color: 'text-emerald-500', bg: 'bg-emerald-500/10' },
        ].map(stat => (
          <Card key={stat.label} className="p-5 glass-card flex items-center gap-4">
            <div className={`p-3 rounded-xl ${stat.bg} ${stat.color}`}>
              <stat.icon className="w-6 h-6" />
            </div>
            <div>
              <p className="text-sm font-medium text-muted-foreground">{stat.label}</p>
              <p className="text-2xl font-bold text-foreground">{stat.value}</p>
            </div>
          </Card>
        ))}
      </div>

      {activeTab === 'analytics' && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="grid gap-6 md:grid-cols-2 mt-6">
          <Card className="p-6 glass-card">
            <h3 className="font-semibold text-lg text-foreground mb-6">Issues by Category</h3>
            <div className="h-72">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={categoryData} cx="50%" cy="50%" innerRadius={70} outerRadius={90} paddingAngle={2} dataKey="value" label>
                    {categoryData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 20px rgba(0,0,0,0.1)' }}/>
                </PieChart>
              </ResponsiveContainer>
            </div>
          </Card>
          <Card className="p-6 glass-card">
            <h3 className="font-semibold text-lg text-foreground mb-6">Resolution Progress</h3>
            <div className="h-72">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={statusData}>
                  <XAxis dataKey="name" axisLine={false} tickLine={false} />
                  <YAxis axisLine={false} tickLine={false} />
                  <Tooltip cursor={{ fill: 'rgba(150,150,150,0.1)' }} contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 20px rgba(0,0,0,0.1)' }} />
                  <Bar dataKey="count" fill="#6366f1" radius={[6, 6, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </Card>
        </motion.div>
      )}

      {activeTab === 'map' && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="mt-6">
          <Card className="p-4 glass-card h-[600px] flex flex-col z-0">
             <h3 className="font-semibold text-lg text-foreground mb-4 shrink-0">Live Issue Map</h3>
             <div className="flex-1 rounded-xl overflow-hidden relative z-0">
               <InteractiveMap issues={issues} />
             </div>
          </Card>
        </motion.div>
      )}

      {activeTab === 'kanban' && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="mt-6">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 h-[600px]">
            {['pending', 'in_progress', 'resolved'].map((status) => (
              <div 
                key={status} 
                className="flex flex-col bg-muted/20 rounded-2xl border border-border p-4 h-full overflow-hidden"
                onDragOver={handleDragOver}
                onDrop={(e) => handleDrop(e, status)}
              >
                <div className="flex items-center justify-between mb-4 px-2 shrink-0">
                  <h3 className="font-semibold text-foreground capitalize flex items-center gap-2">
                    <span className={`w-2.5 h-2.5 rounded-full ${status === 'pending' ? 'bg-amber-500' : status === 'in_progress' ? 'bg-purple-500' : 'bg-emerald-500'}`} />
                    {status.replace('_', ' ')}
                  </h3>
                  <span className="bg-background text-muted-foreground px-2 py-0.5 rounded-full text-xs font-medium border border-border flex items-center justify-center">
                    {getIssuesByStatus(status).length}
                  </span>
                </div>

                <div className="flex-1 overflow-y-auto space-y-3 pr-1" style={{ scrollbarWidth: 'thin' }}>
                  {getIssuesByStatus(status).map(issue => (
                    <div 
                      key={issue.id} 
                      draggable
                      onDragStart={(e) => handleDragStart(e, issue.id)}
                      className="bg-card p-4 rounded-xl shadow-sm border border-border/50 cursor-grab active:cursor-grabbing hover:border-primary/50 transition-colors group relative"
                    >
                      <GripVertical className="absolute right-3 top-4 w-4 h-4 text-muted-foreground opacity-0 group-hover:opacity-100 transition-opacity" />
                      <Link to={`/issues/${issue.id}`} className="block mb-2 font-medium text-sm pr-6 hover:text-primary transition-colors line-clamp-2">
                        {issue.title}
                      </Link>
                      <div className="flex items-center justify-between mt-auto pt-2">
                        <span className="bg-primary/10 text-primary text-[10px] px-2 py-1 rounded-full font-medium truncate max-w-[120px]">
                          {issue.category}
                        </span>
                        <div className="flex items-center gap-1 text-xs text-muted-foreground font-medium bg-muted/50 px-2 py-1 rounded-md">
                          <TrendingUp className="w-3.5 h-3.5" /> {issue.upvotes || 0}
                        </div>
                      </div>
                    </div>
                  ))}
                  {getIssuesByStatus(status).length === 0 && (
                     <div className="h-full min-h-[100px] flex items-center justify-center text-sm text-muted-foreground font-medium border-2 border-dashed border-border rounded-xl">
                       Drag issues here
                     </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        </motion.div>
      )}
    </div>
  )
}

import { useMemo, useState } from 'react'
import { Link } from 'react-router-dom'
import { motion } from 'framer-motion'
import { FileText, Clock, CheckCircle2, TrendingUp, AlertCircle } from 'lucide-react'
import FilterBar from '../components/FilterBar'
import IssueCard from '../components/IssueCard'
import IssueCardSkeleton from '../components/IssueCardSkeleton'
import { Button } from '../components/ui/button'
import { Card } from '../components/ui/card'
import { useIssues } from '../context/IssueContext'

const containerVariants = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: {
      staggerChildren: 0.1
    }
  }
}

export default function DashboardPage() {
  const { issues, loadingIssues, firestoreError } = useIssues()
  const [filter, setFilter] = useState({ category: 'all', status: 'all' })
  const [sortBy, setSortBy] = useState('most_upvoted')

  // The trending algorithm uses a mixture of recency and upvotes to assign a score
  const trendingFiltered = useMemo(() => {
    const now = Date.now() / 1000
    return issues.map(issue => {
        const upvotes = issue.upvotes || 0
        const createdAt = issue.createdAt?.seconds || now
        const ageHours = (now - createdAt) / 3600

        // Priority formula: (upvotes * 10) / (age in hours + 2)^1.5 + (severity weight could be here)
        const priorityScore = (upvotes * 10) / Math.pow(ageHours + 2, 1.5)
        return { ...issue, priorityScore }
      })
      .filter((issue) => (filter.category === 'all' ? true : issue.category === filter.category))
      .filter((issue) => (filter.status === 'all' ? true : issue.status === filter.status))
      .sort((a, b) => b.priorityScore - a.priorityScore)
  }, [issues, filter])

  const sortedFiltered = useMemo(() => {
    return trendingFiltered.slice().sort((a, b) => {
        if (sortBy === 'latest') {
          return (b.createdAt?.seconds || 0) - (a.createdAt?.seconds || 0)
        }
        return (b.upvotes || 0) - (a.upvotes || 0)
    })
  }, [trendingFiltered, sortBy])

  const topUrgent = trendingFiltered.slice(0, 3)
  const resolvedCount = issues.filter((issue) => issue.status === 'resolved').length
  const inProgressCount = issues.filter((issue) => issue.status === 'in_progress').length

  return (
    <div className="space-y-8 animate-in fade-in zoom-in-95 duration-500">
      <motion.div 
        className="rounded-3xl border border-primary/10 bg-gradient-to-br from-primary/10 via-background to-blue-500/5 p-8 relative overflow-hidden glass shadow-sm"
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <div className="absolute top-0 right-0 w-64 h-64 bg-primary/20 rounded-full blur-3xl -z-10 translate-x-1/2 -translate-y-1/2" />
        <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-6 relative z-10">
          <div>
            <h1 className="text-3xl font-extrabold text-foreground tracking-tight sm:text-4xl text-gradient block pb-1">
              Community Dashboard
            </h1>
            <p className="mt-2 text-base text-muted-foreground max-w-xl">
              Discover, prioritize, and track civic issues in your neighborhood. Help your community by reporting problems and upvoting important ones.
            </p>
          </div>
          <Link to="/issues/new" className="shrink-0">
            <Button variant="premium" size="lg" className="rounded-full shadow-glow">
              <AlertCircle className="w-5 h-5 mr-2" /> Report an Issue
            </Button>
          </Link>
        </div>

        <div className="mt-8 grid gap-4 grid-cols-2 md:grid-cols-3">
          <Card className="p-5 glass-card border-none bg-background/50">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-primary/10 text-primary rounded-lg"><FileText className="w-5 h-5" /></div>
              <div>
                <p className="text-sm font-medium text-muted-foreground">Total Issues</p>
                <p className="text-2xl font-bold text-foreground">{issues.length}</p>
              </div>
            </div>
          </Card>
          <Card className="p-5 glass-card border-none bg-background/50">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-blue-500/10 text-blue-500 rounded-lg"><Clock className="w-5 h-5" /></div>
              <div>
                <p className="text-sm font-medium text-muted-foreground">In Progress</p>
                <p className="text-2xl font-bold text-foreground">{inProgressCount}</p>
              </div>
            </div>
          </Card>
          <Card className="p-5 glass-card border-none bg-background/50 md:col-span-1 col-span-2">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-emerald-500/10 text-emerald-500 rounded-lg"><CheckCircle2 className="w-5 h-5" /></div>
              <div>
                <p className="text-sm font-medium text-muted-foreground">Resolved</p>
                <p className="text-2xl font-bold text-foreground">{resolvedCount}</p>
              </div>
            </div>
          </Card>
        </div>
      </motion.div>

      <FilterBar filter={filter} setFilter={setFilter} sortBy={sortBy} setSortBy={setSortBy} />

      {firestoreError && (
        <div className="rounded-xl border border-destructive/20 bg-destructive/10 p-4 text-sm text-destructive flex items-center gap-2">
          <AlertCircle className="w-5 h-5" /> {firestoreError}
        </div>
      )}

      {topUrgent.length > 0 && !loadingIssues && filter.category === 'all' && filter.status === 'all' && (
        <section className="space-y-4">
          <div className="flex items-center gap-2">
            <h2 className="text-xl font-bold text-foreground flex items-center gap-2">
              <TrendingUp className="w-6 h-6 text-rose-500" /> Trending & Urgent
            </h2>
          </div>
          <motion.div 
            variants={containerVariants}
            initial="hidden"
            animate="show"
            className="grid gap-6 md:grid-cols-2 xl:grid-cols-3"
          >
            {topUrgent.map((issue) => (
              <IssueCard key={issue.id} issue={issue} isTrending />
            ))}
          </motion.div>
        </section>
      )}

      <section className="space-y-4">
        <h2 className="text-xl font-bold text-foreground">All Reported Issues</h2>
        {loadingIssues ? (
          <div className="grid gap-6 md:grid-cols-2 xl:grid-cols-3">
            {Array.from({ length: 6 }).map((_, index) => (
              <IssueCardSkeleton key={`all-skeleton-${index}`} />
            ))}
          </div>
        ) : (
          <motion.div 
            variants={containerVariants}
            initial="hidden"
            animate="show"
            className="grid gap-6 md:grid-cols-2 xl:grid-cols-3"
          >
            {sortedFiltered.map((issue) => (
              <IssueCard key={issue.id} issue={issue} />
            ))}
          </motion.div>
        )}

        {!loadingIssues && !sortedFiltered.length ? (
          <motion.div 
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="col-span-full border-2 border-dashed border-border rounded-2xl p-12 text-center bg-card/30 glass"
          >
            <div className="w-16 h-16 bg-muted rounded-full flex items-center justify-center mx-auto mb-4 text-muted-foreground">
              <AlertCircle className="w-8 h-8" />
            </div>
            <h3 className="text-lg font-semibold text-foreground">No issues found</h3>
            <p className="mt-2 text-muted-foreground max-w-sm mx-auto">
              We couldn't find any issues matching your active filters. Try clearing them or report a new one.
            </p>
            <Button variant="outline" className="mt-6" onClick={() => setFilter({ category: 'all', status: 'all' })}>
              Clear Filters
            </Button>
          </motion.div>
        ) : null}
      </section>
    </div>
  )
}

import { CalendarClock, CheckCircle2, Clock3, Mail, PlusCircle, Trophy, Medal, Star, Award } from 'lucide-react'
import { useMemo, useState } from 'react'
import { Link } from 'react-router-dom'
import { motion } from 'framer-motion'
import IssueCard from '../components/IssueCard'
import { Button } from '../components/ui/button'
import { Card } from '../components/ui/card'
import { useAuth } from '../context/AuthContext'
import { useIssues } from '../context/IssueContext'

const containerVariants = {
  hidden: { opacity: 0 },
  show: { opacity: 1, transition: { staggerChildren: 0.1 } }
}

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  show: { opacity: 1, y: 0 }
}

export default function ProfilePage() {
  const { user } = useAuth()
  const { issues } = useIssues()
  const [statusFilter, setStatusFilter] = useState('all')

  const myIssues = useMemo(() => issues.filter((item) => item.userId === user?.uid), [issues, user])
  const resolvedCount = myIssues.filter((item) => item.status === 'resolved').length
  const pendingCount = myIssues.filter((item) => item.status === 'pending').length
  const inProgressCount = myIssues.filter((item) => item.status === 'in_progress').length
  const totalUpvotes = myIssues.reduce((sum, item) => sum + (item.upvotes || 0), 0)

  const filteredIssues = myIssues.filter((item) => (statusFilter === 'all' ? true : item.status === statusFilter))
  const latestIssue = myIssues.sort((a,b) => (b.createdAt?.seconds || 0) - (a.createdAt?.seconds || 0))[0]

  // Gamification logic
  const reputationScore = (myIssues.length * 50) + (totalUpvotes * 10) + (resolvedCount * 100)

  const getBadge = (score) => {
    if (score >= 1000) return { title: 'Local Hero', icon: Trophy, color: 'text-yellow-500', bg: 'bg-yellow-500/10', border: 'border-yellow-500/20' }
    if (score >= 500) return { title: 'Community Leader', icon: Star, color: 'text-purple-500', bg: 'bg-purple-500/10', border: 'border-purple-500/20' }
    if (score >= 200) return { title: 'Active Citizen', icon: Medal, color: 'text-blue-500', bg: 'bg-blue-500/10', border: 'border-blue-500/20' }
    return { title: 'Civic Starter', icon: Award, color: 'text-emerald-500', bg: 'bg-emerald-500/10', border: 'border-emerald-500/20' }
  }

  const currentBadge = getBadge(reputationScore)

  return (
    <motion.div variants={containerVariants} initial="hidden" animate="show" className="space-y-8 max-w-6xl mx-auto">
      <motion.div variants={itemVariants} className="relative rounded-3xl border border-primary/20 bg-gradient-to-r from-primary/10 via-background to-blue-500/5 p-8 overflow-hidden glass shadow-sm flex flex-col md:flex-row items-center gap-8">
        <div className="absolute top-0 right-0 w-64 h-64 bg-primary/20 rounded-full blur-3xl -z-10 translate-x-1/2 -translate-y-1/2 pointer-events-none" />

        <div className="relative z-10 w-24 h-24 rounded-full bg-gradient-to-br from-primary to-blue-600 p-1 shrink-0 shadow-glow">
          <div className="w-full h-full rounded-full bg-background flex items-center justify-center text-4xl font-bold text-primary">
            {user?.email?.[0].toUpperCase() || 'U'}
          </div>
          <div className={`absolute -bottom-2 -right-2 p-1.5 rounded-full ${currentBadge.bg} ${currentBadge.color} border-2 border-background`}>
             <currentBadge.icon className="w-5 h-5" />
          </div>
        </div>

        <div className="relative z-10 flex-1 text-center md:text-left">
          <h1 className="text-3xl font-extrabold text-foreground tracking-tight">{user?.email?.split('@')[0]}</h1>
          <p className="inline-flex items-center gap-1.5 text-muted-foreground mt-1">
            <Mail className="h-4 w-4" /> {user?.email}
          </p>
          <div className="mt-4 flex flex-wrap items-center justify-center md:justify-start gap-4">
             <div className={`flex items-center gap-2 px-4 py-2 rounded-full ${currentBadge.bg} border ${currentBadge.border}`}>
               <currentBadge.icon className={`w-4 h-4 ${currentBadge.color}`} />
               <span className={`text-sm font-bold ${currentBadge.color}`}>{currentBadge.title}</span>
             </div>
             <div className="flex items-center gap-2 px-4 py-2 rounded-full bg-background border border-border shadow-sm">
               <span className="text-base font-bold text-foreground">{reputationScore}</span>
               <span className="text-xs text-muted-foreground font-semibold uppercase tracking-wider">Rep Points</span>
             </div>
          </div>
        </div>

        <Link to="/issues/new" className="relative z-10 shrink-0 w-full md:w-auto">
           <Button variant="premium" className="w-full shadow-glow rounded-full h-12 px-6">
             <PlusCircle className="mr-2 w-5 h-5" /> Report New Issue
           </Button>
        </Link>
      </motion.div>

      <motion.div variants={itemVariants} className="grid gap-4 grid-cols-2 md:grid-cols-4">
        {[
          { label: 'Total Reports', value: myIssues.length, icon: CalendarClock, color: 'text-indigo-500', bg: 'bg-indigo-500/10' },
          { label: 'Pending Assessment', value: pendingCount, icon: Clock3, color: 'text-amber-500', bg: 'bg-amber-500/10' },
          { label: 'In Progress', value: inProgressCount, icon: Clock3, color: 'text-blue-500', bg: 'bg-blue-500/10' },
          { label: 'Resolved Successfully', value: resolvedCount, icon: CheckCircle2, color: 'text-emerald-500', bg: 'bg-emerald-500/10' },
        ].map((stat, i) => (
          <Card key={i} className="p-5 glass-card flex flex-col md:flex-row items-center gap-4 text-center md:text-left border-none bg-background/50">
            <div className={`p-3 rounded-xl ${stat.bg} ${stat.color} shrink-0`}>
              <stat.icon className="w-6 h-6" />
            </div>
            <div>
              <p className="text-sm font-medium text-muted-foreground">{stat.label}</p>
              <p className="text-2xl font-bold text-foreground">{stat.value}</p>
            </div>
          </Card>
        ))}
      </motion.div>

      <motion.div variants={itemVariants} className="flex flex-col md:flex-row gap-4 items-center justify-between bg-card p-2 rounded-xl border border-border shadow-sm">
        <div className="flex flex-wrap gap-1 p-1 bg-muted/50 rounded-lg w-full md:w-auto">
          {[
            ['all', 'All Reports'],
            ['pending', 'Pending'],
            ['in_progress', 'In Progress'],
            ['resolved', 'Resolved'],
          ].map(([key, label]) => (
            <button 
              key={key} 
              onClick={() => setStatusFilter(key)}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-all flex-1 md:flex-none ${statusFilter === key ? 'bg-background shadow-sm text-foreground' : 'text-muted-foreground hover:text-foreground hover:bg-background/50'}`}
            >
              {label}
            </button>
          ))}
        </div>
        {latestIssue && (
           <div className="hidden lg:flex items-center gap-2 px-4 text-sm text-muted-foreground">
              <span className="font-semibold text-foreground">Latest:</span> 
              <span className="truncate max-w-[250px]">{latestIssue.title}</span>
           </div>
        )}
      </motion.div>

      <motion.div variants={itemVariants} className="grid gap-6 md:grid-cols-2 xl:grid-cols-3">
        {filteredIssues.map((issue) => (
          <IssueCard key={issue.id} issue={issue} />
        ))}
        {!filteredIssues.length && (
          <div className="col-span-full border-2 border-dashed border-border rounded-2xl p-12 text-center bg-card/30 glass">
            <div className="w-16 h-16 bg-muted rounded-full flex items-center justify-center mx-auto mb-4 text-muted-foreground">
              <CheckCircle2 className="w-8 h-8" />
            </div>
            <h3 className="text-lg font-semibold text-foreground">No reports found</h3>
            <p className="mt-2 text-muted-foreground max-w-sm mx-auto">
              You haven't reported any issues matching this status yet. Make a difference by reporting one today!
            </p>
          </div>
        )}
      </motion.div>
    </div>
  )
}

import { useState, useRef } from 'react'
import { useNavigate } from 'react-router-dom'
import { motion, AnimatePresence } from 'framer-motion'
import { Camera, MapPin, Sparkles, X, Loader2 } from 'lucide-react'
import { toast } from 'sonner'
import { Button } from '../components/ui/button'
import { Card } from '../components/ui/card'
import { Input } from '../components/ui/input'
import { Textarea } from '../components/ui/textarea'
import { useAuth } from '../context/AuthContext'
import { useIssues } from '../context/IssueContext'
import { ISSUE_CATEGORIES } from '../utils/constants'

export default function ReportIssuePage() {
  const { user } = useAuth()
  const { createIssue } = useIssues()
  const navigate = useNavigate()

  const [loading, setLoading] = useState(false)
  const [aiLoading, setAiLoading] = useState(false)
  const [previewUrl, setPreviewUrl] = useState(null)

  const fileInputRef = useRef(null)

  const [form, setForm] = useState({
    title: '',
    description: '',
    category: ISSUE_CATEGORIES[0],
    location: '',
    image: null,
  })

  // Mock AI Categorization
  const handleAutoCategorize = () => {
    if (!form.description) {
      toast.error('Please enter a description first')
      return
    }

    setAiLoading(true)

    setTimeout(() => {
      // Very simple mock logic
      const desc = form.description.toLowerCase()
      let suggestedCategory = ISSUE_CATEGORIES[0]

      if (desc.includes('road') || desc.includes('pothole') || desc.includes('traffic')) suggestedCategory = 'Infrastructure'
      else if (desc.includes('water') || desc.includes('pipe') || desc.includes('leak')) suggestedCategory = 'Water Supply'
      else if (desc.includes('light') || desc.includes('power') || desc.includes('electricity') || desc.includes('wire')) suggestedCategory = 'Electricity'
      else if (desc.includes('trash') || desc.includes('garbage') || desc.includes('waste') || desc.includes('dump')) suggestedCategory = 'Waste Management'

      setForm(prev => ({ ...prev, category: suggestedCategory }))
      setAiLoading(false)
      toast.success(`AI categorized as ${suggestedCategory}`, {
        icon: <Sparkles className="w-4 h-4 text-emerald-500" />
      })
    }, 1500)
  }

  const handleImageChange = (e) => {
    const file = e.target.files?.[0]
    if (file) {
      setForm(p => ({ ...p, image: file }))
      // Create preview URL
      const reader = new FileReader()
      reader.onloadend = () => {
        setPreviewUrl(reader.result)
      }
      reader.readAsDataURL(file)
    }
  }

  const removeImage = () => {
    setForm(p => ({ ...p, image: null }))
    setPreviewUrl(null)
    if (fileInputRef.current) fileInputRef.current.value = ''
  }

  async function handleSubmit(e) {
    e.preventDefault()
    setLoading(true)

    try {
      await createIssue(form, user.uid)
      toast.success('Issue submitted successfully', {
        description: 'Thank you for reporting this to the community.'
      })
      navigate('/home')
    } catch (err) {
      toast.error('Failed to submit issue', {
        description: err.message || 'Please try again later.'
      })
    } finally {
      setLoading(false)
    }
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="max-w-2xl mx-auto w-full"
    >
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-foreground tracking-tight">Report an Issue</h1>
        <p className="mt-2 text-muted-foreground hidden sm:block">
          Help improve your community by reporting local issues. AI will help categorize it automatically to alert the right authorities.
        </p>
      </div>

      <Card className="p-6 md:p-8 glass-card border-border/50 relative overflow-hidden shadow-soft">
        <div className="absolute top-0 right-0 w-64 h-64 bg-primary/5 rounded-full blur-3xl -z-10 translate-x-1/2 -translate-y-1/2 pointer-events-none" />

        <form className="space-y-6 relative z-10" onSubmit={handleSubmit}>

          <div className="space-y-2">
            <label className="text-sm font-medium text-foreground">Issue Title <span className="text-destructive">*</span></label>
            <Input 
              placeholder="E.g., Large pothole on Main St..." 
              value={form.title} 
              onChange={e => setForm(p => ({ ...p, title: e.target.value }))} 
              required 
              className="bg-background/50 focus:bg-background transition-colors"
            />
          </div>

          <div className="space-y-2 relative">
            <div className="flex items-center justify-between">
              <label className="text-sm font-medium text-foreground">Description <span className="text-destructive">*</span></label>
              <Button 
                type="button" 
                variant="ghost" 
                size="sm" 
                onClick={handleAutoCategorize}
                disabled={aiLoading || !form.description}
                className="h-8 text-xs text-primary hover:text-primary hover:bg-primary/10 gap-1.5"
              >
                {aiLoading ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Sparkles className="w-3.5 h-3.5" />}
                Auto-categorize
              </Button>
            </div>
            <Textarea 
              placeholder="Describe the issue in detail..." 
              value={form.description} 
              onChange={e => setForm(p => ({ ...p, description: e.target.value }))} 
              required 
              className="min-h-[120px] bg-background/50 focus:bg-background transition-colors resize-y"
            />
          </div>

          <div className="grid gap-6 md:grid-cols-2">
            <div className="space-y-2">
              <label className="text-sm font-medium text-foreground">Category <span className="text-destructive">*</span></label>
              <select 
                className="flex h-10 w-full rounded-md border border-input bg-background/50 px-3 py-2 text-sm ring-offset-background focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 transition-colors cursor-pointer"
                value={form.category} 
                onChange={e => setForm(p => ({ ...p, category: e.target.value }))}
                required
              >
                {ISSUE_CATEGORIES.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium text-foreground">Location <span className="text-destructive">*</span></label>
              <div className="relative">
                <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input 
                  placeholder="Street name, landmark..." 
                  value={form.location} 
                  onChange={e => setForm(p => ({ ...p, location: e.target.value }))} 
                  required 
                  className="pl-9 bg-background/50 focus:bg-background transition-colors"
                />
              </div>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-foreground">Photo Evidence</label>

            <AnimatePresence mode="wait">
              {previewUrl ? (
                <motion.div 
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={{ opacity: 0, scale: 0.95 }}
                  className="relative rounded-xl border border-border bg-muted/30 p-2 overflow-hidden aspect-video md:aspect-[21/9] group"
                >
                  <img src={previewUrl} alt="Preview" className="w-full h-full object-cover rounded-lg" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <Button type="button" variant="destructive" size="sm" onClick={removeImage} className="gap-2 shadow-sm border-none">
                      <X className="w-4 h-4" /> Remove Photo
                    </Button>
                  </div>
                </motion.div>
              ) : (
                <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                >
                  <label className="flex flex-col items-center justify-center w-full h-40 border-2 border-dashed border-border rounded-xl cursor-pointer bg-muted/20 hover:bg-muted/50 hover:border-primary/50 transition-all group">
                    <div className="flex flex-col items-center justify-center pt-5 pb-6">
                      <div className="w-12 h-12 bg-background rounded-full shadow-[0_4px_20px_-2px_rgba(0,0,0,0.05)] flex items-center justify-center mb-3 group-hover:scale-110 group-hover:shadow-glow transition-all">
                        <Camera className="w-6 h-6 text-muted-foreground group-hover:text-primary transition-colors" />
                      </div>
                      <p className="mb-1 text-sm text-foreground font-medium">
                        Click to upload an image
                      </p>
                      <p className="text-xs text-muted-foreground">PNG, JPG, GIF (Max 5MB)</p>
                    </div>
                    <input 
                      ref={fileInputRef}
                      type="file" 
                      className="hidden" 
                      accept="image/*" 
                      onChange={handleImageChange} 
                    />
                  </label>
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          <div className="pt-4 border-t border-border/50">
            <Button 
              type="submit" 
              variant="premium" 
              className="w-full h-12 text-base font-semibold" 
              disabled={loading}
            >
              {loading ? (
                <>
                  <Loader2 className="w-5 h-5 mr-2 animate-spin" /> Submitting...
                </>
              ) : (
                'Submit Issue'
              )}
            </Button>
          </div>
        </form>
      </Card>
    </motion.div>
  )
}
